import { BrowserWindow, ipcMain } from 'electron'
import { PtyManager } from '../../pty-manager.js'
import { SessionStore } from '../../session-store.js'
import { ApiServerManager } from '../../api-server.js'
import { pendingApiPrompts, autoCloseSessions } from '../api-prompt-handler.js'

function maybeRespondToCursorPositionRequest(
  ptyManager: PtyManager,
  ptyToBackend: Map<string, string>,
  ptyId: string,
  data: string
): void {
  const backend = ptyToBackend.get(ptyId)
  if (!backend || backend === 'claude') return
  if (data.includes('\x1b[6n') || data.includes('\x1b[?6n')) {
    ptyManager.write(ptyId, '\x1b[1;1R')
  }
}

export function registerPtyHandlers(
  ptyManager: PtyManager,
  sessionStore: SessionStore,
  apiServerManager: ApiServerManager,
  ptyToProject: Map<string, string>,
  ptyToBackend: Map<string, string>,
  getMainWindow: () => BrowserWindow | null
): void {
  ipcMain.handle('pty:spawn', (_, { cwd, sessionId, model, backend }: { cwd: string; sessionId?: string; model?: string; backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider' }) => {
    try {
      const workspace = sessionStore.getWorkspace()
      const project = workspace.projects.find(p => p.path === cwd)
      const globalSettings = sessionStore.getSettings()

      const normalizedGlobalBackend = globalSettings.backend === 'default'
        ? undefined
        : globalSettings.backend

      const normalizedBackend = backend === 'default' ? undefined : backend
      const effectiveBackend = normalizedBackend
        || (project?.backend && project.backend !== 'default'
          ? project.backend
          : normalizedGlobalBackend || 'claude')

      const pending = pendingApiPrompts.get(cwd)
      const effectiveModel = model || pending?.model
      const autoAcceptTools = project?.autoAcceptTools ?? globalSettings.autoAcceptTools
      const permissionMode = project?.permissionMode ?? globalSettings.permissionMode

      const id = ptyManager.spawn(cwd, sessionId, autoAcceptTools, permissionMode, effectiveModel, effectiveBackend)
      ptyToProject.set(id, cwd)
      ptyToBackend.set(id, effectiveBackend)

      if (project?.apiPort && project.apiAutoStart && !apiServerManager.isRunning(cwd)) {
        apiServerManager.start(cwd, project.apiPort)
      }

      const mainWindow = getMainWindow()

      ptyManager.onData(id, (data) => {
        maybeRespondToCursorPositionRequest(ptyManager, ptyToBackend, id, data)
        try {
          mainWindow?.webContents.send(`pty:data:${id}`, data)
        } catch (e) {
          console.error('IPC send failed', e)
        }
      })

      ptyManager.onExit(id, (code) => {
        try {
          mainWindow?.webContents.send(`pty:exit:${id}`, code)
        } catch (e) {
          console.error('IPC send failed', e)
        }
        ptyToProject.delete(id)
        ptyToBackend.delete(id)
        autoCloseSessions.delete(id)
      })

      if (pending) {
        pendingApiPrompts.delete(cwd)
        if (pending.autoClose) autoCloseSessions.add(id)
        setTimeout(() => {
          ptyManager.write(id, pending.prompt + '\n')
          pending.resolve({ success: true, message: 'Prompt sent to new terminal', sessionCreated: true })
        }, 4000)
      }

      return id
    } catch (error: any) {
      console.error('Failed to spawn PTY:', error)
      throw new Error(`Failed to start Claude: ${error.message}`)
    }
  })

  ipcMain.on('pty:write', (_, { id, data }: { id: string; data: string }) => ptyManager.write(id, data))
  ipcMain.on('pty:resize', (_, { id, cols, rows }: { id: string; cols: number; rows: number }) => ptyManager.resize(id, cols, rows))
  ipcMain.on('pty:kill', (_, id: string) => {
    ptyToProject.delete(id)
    ptyToBackend.delete(id)
    ptyManager.kill(id)
  })

  ipcMain.handle('pty:set-backend', async (_, { id: oldId, backend: newBackend }: { id: string; backend: 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider' }) => {
    const process = ptyManager.getProcess(oldId)
    if (!process) return

    const { cwd, sessionId, backend: oldBackend } = process
    const effectiveSessionId = oldBackend !== newBackend ? undefined : sessionId

    ptyManager.kill(oldId)
    const newId = ptyManager.spawn(cwd, effectiveSessionId, undefined, undefined, undefined, newBackend)

    const projectPath = ptyToProject.get(oldId)
    if (projectPath) {
      ptyToProject.set(newId, projectPath)
      ptyToProject.delete(oldId)
    }
    ptyToBackend.set(newId, newBackend)
    ptyToBackend.delete(oldId)

    const mainWindow = getMainWindow()

    ptyManager.onData(newId, (data) => {
      maybeRespondToCursorPositionRequest(ptyManager, ptyToBackend, newId, data)
      mainWindow?.webContents.send(`pty:data:${newId}`, data)
    })

    ptyManager.onExit(newId, (code) => {
      mainWindow?.webContents.send(`pty:exit:${newId}`, code)
      ptyToProject.delete(newId)
      ptyToBackend.delete(newId)
    })

    mainWindow?.webContents.send('pty:recreated', { oldId, newId, backend: newBackend })
  })
}

import { app } from 'electron'
import { existsSync, mkdirSync, readFileSync, writeFileSync, renameSync, statSync } from 'fs'
import { join } from 'path'
import { syncMetaProjects } from './meta-project-sync'

export interface ProjectCategory {
  id: string
  name: string
  collapsed: boolean
  order: number
}

export interface Project {
  path: string
  name: string
  executable?: string
  apiPort?: number  // Port for HTTP API to send prompts to terminal
  apiAutoStart?: boolean  // Whether to auto-start API when session opens (default: false)
  apiSessionMode?: 'existing' | 'new-keep' | 'new-close'  // How API requests handle sessions
  apiModel?: 'default' | 'opus' | 'sonnet' | 'haiku'  // Model for API-triggered sessions
  autoAcceptTools?: string[]  // Per-project tool patterns to auto-accept
  permissionMode?: string     // Per-project permission mode
  color?: string              // Project color for visual identification
  ttsVoice?: string           // Per-project TTS voice (overrides global)
  ttsEngine?: 'piper' | 'xtts'  // Per-project TTS engine
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider' // Per-project backend (overrides global)
  categoryId?: string         // Category this project belongs to
  order?: number              // Order within category or uncategorized list
}

export interface OpenTab {
  id: string
  projectPath: string
  sessionId?: string
  title: string
  ptyId?: string
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
}

export interface TileLayout {
  id: string
  tabIds: string[]
  activeTabId: string
  x: number
  y: number
  width: number
  height: number
}

export interface Workspace {
  projects: Project[]
  openTabs: OpenTab[]
  activeTabId: string | null
  viewMode?: 'tabs' | 'tiled'
  tileLayout?: TileLayout[]
  categories?: ProjectCategory[]
}

export interface WindowBounds {
  x: number
  y: number
  width: number
  height: number
}

export interface ThemeCustomization {
  accentColor: string | null
  backgroundColor: string | null
  textColor: string | null
  terminalColors: {
    black?: string
    red?: string
    green?: string
    yellow?: string
    blue?: string
    magenta?: string
    cyan?: string
    white?: string
  } | null
}

export interface Settings {
  defaultProjectDir: string
  theme: string
  themeCustomization?: ThemeCustomization | null
  voiceOutputEnabled?: boolean
  voiceVolume?: number
  voiceSpeed?: number
  voiceSkipOnNew?: boolean
  voiceSilenceThreshold?: number
  autoAcceptTools?: string[]
  permissionMode?: string
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
}


interface StoredData {
  workspace: Workspace
  windowBounds?: WindowBounds
  settings?: Settings
}

export class SessionStore {
  private configPath: string
  private backupPath: string
  private data: StoredData

  constructor() {
    const configDir = join(app.getPath('userData'), 'config')
    if (!existsSync(configDir)) {
      mkdirSync(configDir, { recursive: true })
    }
    this.configPath = join(configDir, 'workspace.json')
    this.backupPath = join(configDir, 'workspace.json.backup')
    this.data = this.load()
  }

  private loadFile(path: string): StoredData | null {
    try {
      if (!existsSync(path)) return null
      const stat = statSync(path)
      if (stat.size === 0) return null
      const content = readFileSync(path, 'utf-8')
      const data = JSON.parse(content)
      if (!data?.workspace) return null
      return data
    } catch (e) {
      console.error(`[SessionStore] Failed to load ${path}:`, e)
      return null
    }
  }

  private load(): StoredData {
    // Try main file first
    const main = this.loadFile(this.configPath)
    if (main && (main.workspace.projects?.length || 0) > 0) {
      return main
    }

    // Main file is empty/corrupt/missing — try backup
    const backup = this.loadFile(this.backupPath)
    if (backup && (backup.workspace.projects?.length || 0) > 0) {
      console.log('[SessionStore] Main config empty/corrupt, restored from backup (' +
        backup.workspace.projects.length + ' projects)')
      // Restore backup as main file immediately
      try {
        writeFileSync(this.configPath, JSON.stringify(backup, null, 2))
      } catch (e) {
        console.error('[SessionStore] Failed to restore backup to main:', e)
      }
      return backup
    }

    // If main loaded but had 0 projects (valid empty state), use it
    if (main) return main

    return {
      workspace: {
        projects: [],
        openTabs: [],
        activeTabId: null
      }
    }
  }

  private save(): void {
    try {
      const json = JSON.stringify(this.data, null, 2)

      // Validate we can parse what we're about to write
      JSON.parse(json)

      // Back up existing file before overwriting (if it has content)
      if (existsSync(this.configPath)) {
        try {
          const stat = statSync(this.configPath)
          if (stat.size > 0) {
            // Only update backup if existing file is valid and has projects
            const existing = this.loadFile(this.configPath)
            if (existing && (existing.workspace.projects?.length || 0) > 0) {
              writeFileSync(this.backupPath, readFileSync(this.configPath))
            }
          }
        } catch (e) {
          console.error('[SessionStore] Failed to update backup:', e)
        }
      }

      // Atomic write: write to temp file, then rename
      const tmpPath = this.configPath + '.tmp'
      writeFileSync(tmpPath, json)

      // Verify the temp file was written completely
      const written = readFileSync(tmpPath, 'utf-8')
      JSON.parse(written) // throws if truncated/corrupt

      renameSync(tmpPath, this.configPath)
    } catch (e) {
      console.error('[SessionStore] Failed to save workspace:', e)
    }
  }

  getWorkspace(): Workspace {
    return this.data.workspace
  }

  // Reload workspace from disk (useful when file was modified externally)
  reloadFromDisk(): void {
    console.log('[SessionStore] Reloading workspace from disk')
    this.data = this.load()
    console.log('[SessionStore] Reloaded, projects:', this.data.workspace?.projects?.length || 0)
  }

  saveWorkspace(workspace: Workspace): void {
    // Protect against overwriting populated workspace with empty one
    const incomingProjects = workspace?.projects?.length || 0
    const currentProjects = this.data.workspace?.projects?.length || 0
    if (incomingProjects === 0 && currentProjects > 0) {
      console.log('[SessionStore] Rejected empty workspace save - current has', currentProjects, 'projects')
      return
    }
    this.data.workspace = workspace
    this.save()
    syncMetaProjects(workspace)
  }

  getWindowBounds(): WindowBounds | undefined {
    return this.data.windowBounds
  }

  saveWindowBounds(bounds: WindowBounds): void {
    this.data.windowBounds = bounds
    this.save()
  }

  getSettings(): Settings {
    return this.data.settings ?? { defaultProjectDir: '', theme: 'default', backend: 'default' }
  }

  saveSettings(settings: Settings): void {
    this.data.settings = settings
    this.save()
  }
}

