import { ipcRenderer, IpcRendererEvent } from 'electron'

type Backend = 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'

export const ptyHandlers = {
  spawnPty: (cwd: string, sessionId?: string, model?: string, backend?: Backend): Promise<string> =>
    ipcRenderer.invoke('pty:spawn', { cwd, sessionId, model, backend }),

  writePty: (id: string, data: string): void => ipcRenderer.send('pty:write', { id, data }),

  resizePty: (id: string, cols: number, rows: number): void => ipcRenderer.send('pty:resize', { id, cols, rows }),

  killPty: (id: string): void => ipcRenderer.send('pty:kill', id),

  setPtyBackend: (id: string, backend: Backend): Promise<void> =>
    ipcRenderer.invoke('pty:set-backend', { id, backend }),

  onPtyData: (id: string, callback: (data: string) => void): (() => void) => {
    const handler = (_: IpcRendererEvent, data: string) => callback(data)
    ipcRenderer.on(`pty:data:${id}`, handler)
    return () => ipcRenderer.removeListener(`pty:data:${id}`, handler)
  },

  onPtyExit: (id: string, callback: (code: number) => void): (() => void) => {
    const handler = (_: IpcRendererEvent, code: number) => callback(code)
    ipcRenderer.on(`pty:exit:${id}`, handler)
    return () => ipcRenderer.removeListener(`pty:exit:${id}`, handler)
  },

  onPtyRecreated: (callback: (data: { oldId: string; newId: string; backend: Backend }) => void): (() => void) => {
    const handler = (_: IpcRendererEvent, data: { oldId: string; newId: string; backend: Backend }) => callback(data)
    ipcRenderer.on('pty:recreated', handler)
    return () => ipcRenderer.removeListener('pty:recreated', handler)
  }
}

/**
 * PTY Routes - /api/pty/* endpoints
 */

import { Express, Request, Response } from 'express'
import { WebSocket } from 'ws'
import { validateProjectPath } from '../../mobile-security'
import { log } from '../utils'
import { LocalPty } from '../types'

export function setupPtyRoutes(
  app: Express,
  getPtyManager: () => any,
  getLocalPtys: () => Map<string, LocalPty>,
  getPtyStreams: () => Map<string, Set<WebSocket>>,
  getPtyDataBuffer: () => Map<string, string[]>,
  broadcastPtyData: (ptyId: string, data: string) => void,
  broadcastPtyExit: (ptyId: string, code: number) => void
): void {
  // Spawn a new PTY
  app.post('/api/pty/spawn', async (req: Request, res: Response) => {
    try {
      const { projectPath, sessionId, model, backend } = req.body

      if (!projectPath || typeof projectPath !== 'string') {
        return res.status(400).json({ error: 'projectPath is required' })
      }

      const pathValidation = validateProjectPath(projectPath)
      if (!pathValidation.valid) {
        return res.status(400).json({ error: pathValidation.error })
      }
      const safeProjectPath = pathValidation.normalizedPath!

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      log('PTY spawn request', { projectPath: safeProjectPath, sessionId, model, backend })

      const ptyId = ptyManager.spawn(
        safeProjectPath,
        sessionId,
        undefined, // autoAcceptTools
        undefined, // permissionMode
        model,
        backend
      )

      // Track this PTY for cleanup
      const localPty: LocalPty = {
        ptyId,
        projectPath: safeProjectPath,
        dataCallbacks: new Set(),
        exitCallbacks: new Set()
      }
      getLocalPtys().set(ptyId, localPty)

      // Set up data forwarding to WebSocket streams
      ptyManager.onData(ptyId, (data: string) => {
        broadcastPtyData(ptyId, data)
      })

      // Set up exit handler
      ptyManager.onExit(ptyId, (code: number) => {
        log('PTY exited', { ptyId, code })
        broadcastPtyExit(ptyId, code)
        getLocalPtys().delete(ptyId)
        getPtyStreams().delete(ptyId)
        getPtyDataBuffer().delete(ptyId)
      })

      log('PTY spawned', { ptyId, projectPath })
      res.json({ ptyId })
    } catch (error) {
      log('PTY spawn error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Write data to PTY
  app.post('/api/pty/:id/write', (req: Request, res: Response) => {
    try {
      const { id } = req.params
      const { data } = req.body

      if (!data || typeof data !== 'string') {
        return res.status(400).json({ error: 'data is required and must be a string' })
      }

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.write(id, data)
      log('PTY write', { ptyId: id, dataLength: data.length })
      res.json({ success: true })
    } catch (error) {
      log('PTY write error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Resize PTY
  app.post('/api/pty/:id/resize', (req: Request, res: Response) => {
    try {
      const { id } = req.params
      const { cols, rows } = req.body

      if (typeof cols !== 'number' || typeof rows !== 'number') {
        return res.status(400).json({ error: 'cols and rows are required and must be numbers' })
      }

      if (cols < 1 || rows < 1 || cols > 500 || rows > 500) {
        return res.status(400).json({ error: 'cols and rows must be between 1 and 500' })
      }

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.resize(id, cols, rows)
      log('PTY resize', { ptyId: id, cols, rows })
      res.json({ success: true })
    } catch (error) {
      log('PTY resize error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Kill PTY
  app.delete('/api/pty/:id', (req: Request, res: Response) => {
    try {
      const { id } = req.params

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.kill(id)
      getLocalPtys().delete(id)

      // Close any WebSocket streams for this PTY
      const streams = getPtyStreams().get(id)
      if (streams) {
        streams.forEach(ws => {
          if (ws.readyState === WebSocket.OPEN) {
            ws.close(1000, 'PTY killed')
          }
        })
        getPtyStreams().delete(id)
      }

      log('PTY killed', { ptyId: id })
      res.json({ success: true })
    } catch (error) {
      log('PTY kill error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })
}

/**
 * PTY API Methods
 *
 * PTY management methods for the HTTP backend.
 */

import {
  PtyDataCallback,
  PtyExitCallback,
  PtyRecreatedCallback,
  Unsubscribe,
  BackendId
} from '../types'
import { ConnectionManager } from './connection'
import { PtyWebSocketManager } from './pty-websocket'
import { PtyWebSocketState } from './types'

export class PtyApi {
  private connection: ConnectionManager
  private wsManager: PtyWebSocketManager
  private ptyRecreatedCallbacks: Set<PtyRecreatedCallback> = new Set()

  constructor(connection: ConnectionManager, wsManager: PtyWebSocketManager) {
    this.connection = connection
    this.wsManager = wsManager
  }

  async spawnPty(cwd: string, sessionId?: string, model?: string, backend?: BackendId): Promise<string> {
    this.connection.setConnectionState('connecting')

    const data = await this.connection.fetchJson<{ ptyId: string }>('/api/pty/spawn', {
      method: 'POST',
      body: JSON.stringify({
        projectPath: cwd,
        sessionId,
        model,
        backend
      })
    })

    // Connect WebSocket for this PTY's data stream
    this.wsManager.connectPtyStream(data.ptyId)

    return data.ptyId
  }

  killPty(id: string): void {
    // Disconnect WebSocket first
    this.wsManager.disconnectPtyStream(id)

    // Then send kill request (fire and forget)
    this.connection.fetch(`/api/pty/${id}`, { method: 'DELETE' }).catch((err) => {
      console.error('[HttpBackend] Failed to kill PTY:', err)
    })
  }

  writePty(id: string, data: string): void {
    // Prefer WebSocket if connected
    if (this.wsManager.sendToPty(id, { type: 'input', data })) {
      return
    }

    // Fall back to HTTP
    this.connection
      .fetch(`/api/pty/${id}/write`, {
        method: 'POST',
        body: JSON.stringify({ data })
      })
      .catch((err) => {
        console.error('[HttpBackend] Failed to write to PTY:', err)
      })
  }

  resizePty(id: string, cols: number, rows: number): void {
    // Prefer WebSocket if connected
    if (this.wsManager.sendToPty(id, { type: 'resize', cols, rows })) {
      return
    }

    // Fall back to HTTP
    this.connection
      .fetch(`/api/pty/${id}/resize`, {
        method: 'POST',
        body: JSON.stringify({ cols, rows })
      })
      .catch((err) => {
        console.error('[HttpBackend] Failed to resize PTY:', err)
      })
  }

  onPtyData(id: string, callback: PtyDataCallback): Unsubscribe {
    const ptyWebsockets = this.wsManager.getPtyWebsockets()

    // Ensure WebSocket is connected
    let state = ptyWebsockets.get(id)
    if (!state) {
      // Create state but don't connect yet (might be called before spawnPty returns)
      state = {
        ws: null as any, // Will be set by connectPtyStream
        dataCallbacks: new Set(),
        exitCallbacks: new Set(),
        reconnectAttempts: 0,
        reconnectTimer: null,
        dataBuffer: []
      }
      ptyWebsockets.set(id, state)
    }

    state.dataCallbacks.add(callback)

    // Flush any buffered data to this callback
    if (state.dataBuffer.length > 0) {
      console.log(
        '[HttpBackend] Flushing',
        state.dataBuffer.length,
        'buffered messages to callback for PTY:',
        id
      )
      const bufferedData = [...state.dataBuffer]
      state.dataBuffer = []
      // Send buffered data to all callbacks (not just this one, in case multiple registered)
      for (const data of bufferedData) {
        state.dataCallbacks.forEach((cb) => cb(data))
      }
    }

    // If WebSocket isn't connected, try to connect
    if (!state.ws || state.ws.readyState !== WebSocket.OPEN) {
      this.wsManager.connectPtyStream(id)
    }

    return () => {
      const s = ptyWebsockets.get(id)
      if (s) {
        s.dataCallbacks.delete(callback)
      }
    }
  }

  onPtyExit(id: string, callback: PtyExitCallback): Unsubscribe {
    const ptyWebsockets = this.wsManager.getPtyWebsockets()

    let state = ptyWebsockets.get(id)
    if (!state) {
      state = {
        ws: null as any,
        dataCallbacks: new Set(),
        exitCallbacks: new Set(),
        reconnectAttempts: 0,
        reconnectTimer: null,
        dataBuffer: []
      }
      ptyWebsockets.set(id, state)
    }

    state.exitCallbacks.add(callback)

    return () => {
      const s = ptyWebsockets.get(id)
      if (s) {
        s.exitCallbacks.delete(callback)
      }
    }
  }

  onPtyRecreated(callback: PtyRecreatedCallback): Unsubscribe {
    this.ptyRecreatedCallbacks.add(callback)
    return () => {
      this.ptyRecreatedCallbacks.delete(callback)
    }
  }
}

