/**
 * PTY WebSocket Management
 *
 * Manages WebSocket connections for PTY data streaming.
 */

import { MAX_RECONNECT_ATTEMPTS, RECONNECT_DELAYS } from './constants'
import { PtyWebSocketState } from './types'

export class PtyWebSocketManager {
  private ptyWebsockets: Map<string, PtyWebSocketState> = new Map()
  private wsBaseUrl: string
  private token: string

  constructor(wsBaseUrl: string, token: string) {
    this.wsBaseUrl = wsBaseUrl
    this.token = token
  }

  getPtyWebsockets(): Map<string, PtyWebSocketState> {
    return this.ptyWebsockets
  }

  /**
   * Connect WebSocket for PTY data streaming
   */
  connectPtyStream(ptyId: string): void {
    // Don't reconnect if already connected or connecting
    const existing = this.ptyWebsockets.get(ptyId)
    if (
      existing?.ws &&
      (existing.ws.readyState === WebSocket.OPEN || existing.ws.readyState === WebSocket.CONNECTING)
    ) {
      return
    }

    const url = `${this.wsBaseUrl}/api/pty/${ptyId}/stream?token=${encodeURIComponent(this.token)}`
    console.log('[HttpBackend] Connecting PTY stream:', ptyId)

    const ws = new WebSocket(url)

    // Reuse existing state if available (preserves callbacks), otherwise create new
    const state: PtyWebSocketState = existing || {
      ws,
      dataCallbacks: new Set(),
      exitCallbacks: new Set(),
      reconnectAttempts: 0,
      reconnectTimer: null,
      dataBuffer: []
    }
    // Update the WebSocket reference
    state.ws = ws
    state.reconnectAttempts = existing?.reconnectAttempts || 0

    ws.onopen = () => {
      console.log('[HttpBackend] PTY stream connected:', ptyId)
      state.reconnectAttempts = 0
    }

    ws.onmessage = (event) => {
      try {
        const msg = JSON.parse(event.data)

        switch (msg.type) {
          case 'data':
            // Buffer data if no callbacks registered yet
            if (state.dataCallbacks.size === 0) {
              state.dataBuffer.push(msg.data)
              // Limit buffer size to prevent memory issues
              if (state.dataBuffer.length > 1000) {
                state.dataBuffer.shift()
              }
            } else {
              // Forward data to all callbacks
              state.dataCallbacks.forEach((cb) => cb(msg.data))
            }
            break

          case 'exit':
            // Forward exit to all callbacks
            state.exitCallbacks.forEach((cb) => cb(msg.code))
            // Clean up after exit
            this.ptyWebsockets.delete(ptyId)
            break

          case 'connected':
            console.log(
              '[HttpBackend] PTY stream confirmed:',
              ptyId,
              'callbacks:',
              state.dataCallbacks.size,
              'buffered:',
              state.dataBuffer.length
            )
            break

          case 'pong':
            // Keep-alive response, nothing to do
            break

          default:
            console.log('[HttpBackend] Unknown PTY message type:', msg.type)
        }
      } catch (e) {
        console.error('[HttpBackend] Failed to parse PTY message:', e)
      }
    }

    ws.onerror = (event) => {
      console.error('[HttpBackend] PTY stream error:', ptyId, event)
    }

    ws.onclose = (event) => {
      console.log('[HttpBackend] PTY stream closed:', ptyId, event.code, event.reason)

      // Attempt reconnection if not a clean close and we still want this PTY
      if (!event.wasClean && state.reconnectAttempts < MAX_RECONNECT_ATTEMPTS) {
        const delay =
          RECONNECT_DELAYS[Math.min(state.reconnectAttempts, RECONNECT_DELAYS.length - 1)]
        console.log(`[HttpBackend] Reconnecting PTY stream in ${delay}ms...`)

        state.reconnectTimer = setTimeout(() => {
          state.reconnectAttempts++
          this.connectPtyStream(ptyId)
        }, delay)
      } else if (event.code !== 1000) {
        // Exit callback for abnormal closure
        state.exitCallbacks.forEach((cb) => cb(-1))
        this.ptyWebsockets.delete(ptyId)
      }
    }

    this.ptyWebsockets.set(ptyId, state)
  }

  /**
   * Disconnect PTY WebSocket stream
   */
  disconnectPtyStream(ptyId: string): void {
    const state = this.ptyWebsockets.get(ptyId)
    if (!state) return

    // Clear reconnect timer
    if (state.reconnectTimer) {
      clearTimeout(state.reconnectTimer)
    }

    // Close WebSocket
    if (
      state.ws &&
      (state.ws.readyState === WebSocket.OPEN || state.ws.readyState === WebSocket.CONNECTING)
    ) {
      state.ws.close(1000, 'Client requested close')
    }

    this.ptyWebsockets.delete(ptyId)
  }

  /**
   * Disconnect all PTY WebSocket connections
   */
  disconnectAll(): void {
    this.ptyWebsockets.forEach((state, ptyId) => {
      if (state.reconnectTimer) {
        clearTimeout(state.reconnectTimer)
      }
      if (
        state.ws &&
        (state.ws.readyState === WebSocket.OPEN || state.ws.readyState === WebSocket.CONNECTING)
      ) {
        state.ws.close(1000, 'Client disconnecting')
      }
    })
    this.ptyWebsockets.clear()
  }

  /**
   * Send data to a PTY via WebSocket
   */
  sendToPty(ptyId: string, message: object): boolean {
    const state = this.ptyWebsockets.get(ptyId)
    if (state && state.ws.readyState === WebSocket.OPEN) {
      state.ws.send(JSON.stringify(message))
      return true
    }
    return false
  }
}

import * as os from 'os'
import * as path from 'path'

export const isWindows = process.platform === 'win32'
export const isMac = process.platform === 'darwin'
export const isLinux = process.platform === 'linux'
export const PATH_SEP = isWindows ? ';' : ':'
export const homeDir = os.homedir()

export function getDefaultShell(): string {
  if (isWindows) {
    return process.env.COMSPEC || 'cmd.exe'
  }
  return process.env.SHELL || '/bin/bash'
}

export function getPowerShell(): string {
  return process.env.PROGRAMFILES
    ? path.join(process.env.PROGRAMFILES, 'PowerShell', '7', 'pwsh.exe')
    : 'powershell.exe'
}

export function getAdditionalPaths(): string[] {
  if (isWindows) {
    const appData = process.env.APPDATA || path.join(homeDir, 'AppData', 'Roaming')
    const localAppData = process.env.LOCALAPPDATA || path.join(homeDir, 'AppData', 'Local')
    return [
      path.join(appData, 'npm'),
      path.join(localAppData, 'Programs', 'nodejs'),
      path.join(homeDir, '.local', 'bin'),
      path.join(homeDir, '.cargo', 'bin'),
    ]
  }

  return [
    path.join(homeDir, '.nvm/versions/node/v20.18.1/bin'),
    path.join(homeDir, '.nvm/versions/node/v22.11.0/bin'),
    path.join(homeDir, '.local/bin'),
    path.join(homeDir, '.npm-global/bin'),
    path.join(homeDir, '.cargo', 'bin'),
    '/usr/local/bin',
  ]
}

export function getEnhancedPath(): string {
  const additionalPaths = getAdditionalPaths()
  const currentPath = process.env.PATH || ''
  return [...additionalPaths, currentPath].join(PATH_SEP)
}

let portableBinDirs: string[] = []

export function setPortableBinDirs(dirs: string[]): void {
  portableBinDirs = dirs
}

export function getEnhancedPathWithPortable(): string {
  const additionalPaths = getAdditionalPaths()
  const currentPath = process.env.PATH || ''
  return [...portableBinDirs, ...additionalPaths, currentPath].join(PATH_SEP)
}

import React, { useEffect, useState, useCallback, useRef } from 'react'
import '@xterm/xterm/css/xterm.css'
import { TerminalBar } from '../TerminalBar.js'
import { AutoWorkOptions } from '../TerminalMenu.js'
import { CustomCommandModal } from '../CustomCommandModal.js'
import { resolveBackendCommand } from '../../utils/backendCommands.js'
import type { TerminalProps } from './types.js'
import { useTerminalSetup } from './useTerminalSetup.js'
import { useTTS } from './useTTS.js'
import { useAutoWork } from './useAutoWork.js'
import { useSummaryCapture } from './useSummaryCapture.js'
import { clearTerminalBuffer, cleanupOrphanedBuffers, formatPathsForBackend } from './utils.js'

// Re-export buffer utilities for external use
export { clearTerminalBuffer, cleanupOrphanedBuffers }

/**
 * Terminal component that wraps xterm.js with PTY integration.
 * Supports TTS, auto work loop, summary capture, and backend-specific commands.
 */
export function Terminal({ ptyId, isActive, theme, onFocus, projectPath, backend, api, isMobile, onOpenFileBrowser }: TerminalProps): React.ReactElement {
  // Custom command modal state
  const [showCustomCommandModal, setShowCustomCommandModal] = useState(false)

  // PTY write helper - uses api if provided, otherwise window.electronAPI
  const writePty = useCallback((id: string, data: string) => {
    if (api) {
      api.writePty(id, data)
    } else {
      window.electronAPI?.writePty(id, data)
    }
  }, [api])

  // Backend change handler
  const handleBackendChange = useCallback((newBackend: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider') => {
    if (newBackend === 'default') return
    api?.setPtyBackend?.(ptyId, newBackend)
    window.electronAPI?.setPtyBackend?.(ptyId, newBackend)
  }, [api, ptyId])

  // Send backend-specific command
  const sendBackendCommand = useCallback((commandId: string): boolean => {
    const backendCommand = resolveBackendCommand(backend, commandId)
    if (!backendCommand) {
      return false
    }
    writePty(ptyId, backendCommand)
    setTimeout(() => {
      writePty(ptyId, '\r')
    }, 100)
    return true
  }, [backend, ptyId, writePty])

  // TTS hook
  const {
    processTTSChunk,
    handleUserInput,
    resetTTSState,
    prePopulateSpokenContent,
  } = useTTS({ ptyId, isActive })

  // Auto work hook (needs summary capture's triggerSummarize)
  // We'll wire it up after summary capture is created
  const autoWorkHookPlaceholder = useAutoWork({
    ptyId,
    sendBackendCommand,
    triggerSummarize: () => {}, // Will be replaced
  })

  // Summary capture hook
  const {
    processSummaryChunk,
    triggerSummarize,
  } = useSummaryCapture({
    ptyId,
    sendBackendCommand,
    autoWorkWithSummary: autoWorkHookPlaceholder.autoWorkState.withSummary,
    buildAutoWorkPrompt: autoWorkHookPlaceholder.buildAutoWorkPrompt,
  })

  // Reconnect auto work with actual triggerSummarize
  const {
    autoWorkState,
    awaitingUserReview,
    handleAutoWorkMarker,
    startAutoWork,
    continueAutoWork,
    stopAutoWork,
    cancelAutoWork,
  } = useAutoWork({
    ptyId,
    sendBackendCommand,
    triggerSummarize,
  })

  // Terminal setup hook
  const {
    containerRef,
    terminalRef,
    fitAddonRef,
    userScrolledUpRef,
    currentLineInputRef,
    inputSuppressedRef,
  } = useTerminalSetup({
    ptyId,
    theme,
    backend,
    api,
    onTTSChunk: processTTSChunk,
    onUserInput: handleUserInput,
    onSummaryChunk: processSummaryChunk,
    onAutoWorkMarker: handleAutoWorkMarker,
    prePopulateSpokenContent,
    resetTTSState,
  })

  // Refit when tab becomes active
  useEffect(() => {
    if (isActive && fitAddonRef.current && containerRef.current && terminalRef.current) {
      const doFit = () => {
        if (!fitAddonRef.current || !containerRef.current || !terminalRef.current) return

        const rect = containerRef.current.getBoundingClientRect()
        if (rect.width > 50 && rect.height > 50) {
          const wasAtBottom = !userScrolledUpRef.current

          fitAddonRef.current.fit()
          const dims = fitAddonRef.current.proposeDimensions()
          if (dims && dims.cols > 0 && dims.rows > 0) {
            window.electronAPI?.resizePty(ptyId, dims.cols, dims.rows)
          }
          if (wasAtBottom) {
            requestAnimationFrame(() => {
              terminalRef.current?.scrollToBottom()
            })
          }
        }
        terminalRef.current?.focus()
