        userScrolledUpRef,
        ptyOperations,
        ptyId,
        onTTSChunk,
        onSummaryChunk,
        onAutoWorkMarker,
        state
      )
    })

    // PTY exit handling
    cleanupExit = ptyOperations.onPtyExit(ptyId, (code) => {
      handlePtyExit(code, state.terminal, ptyId, state)
    })

