        projects,
        openTabs: openTabs.map(t => ({
          id: t.id,
          projectPath: t.projectPath,
          sessionId: t.sessionId,
          title: t.title,
          ptyId: t.ptyId,
          backend: t.backend
        })),
        activeTabId,
        viewMode,
        tileLayout,
        categories
      })
    }

import React, { useCallback, memo, RefObject } from 'react'
import { OpenTab } from '../stores/workspace'
import { useIsMobile } from '../hooks/useIsMobile'
import { useSwipeGesture } from '../hooks/useSwipeGesture'
import { SwipeDots } from './mobile/SwipeDots'

interface TabItemProps {
  tab: OpenTab
  isActive: boolean
  onSelect: (id: string) => void
  onClose: (id: string) => void
  onNewSession: (projectPath: string) => void
}

const TabItem = memo(function TabItem({ tab, isActive, onSelect, onClose, onNewSession }: TabItemProps) {
  const handleClick = useCallback(() => {
    onSelect(tab.id)
  }, [onSelect, tab.id])

  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault()
      onSelect(tab.id)
    }
  }, [onSelect, tab.id])

  const handleClose = useCallback((e: React.MouseEvent) => {
    e.stopPropagation()
    onClose(tab.id)
  }, [onClose, tab.id])

  const handleNewSession = useCallback((e: React.MouseEvent) => {
    e.stopPropagation()
    onNewSession(tab.projectPath)
  }, [onNewSession, tab.projectPath])

  return (
    <div
      className={`tab ${isActive ? 'active' : ''}`}
      role="tab"
      aria-selected={isActive}
      tabIndex={0}
      onClick={handleClick}
      onKeyDown={handleKeyDown}
    >
      <span className="tab-title" title={tab.title}>{tab.title}</span>
      <button
        className="tab-new-session"
        onClick={handleNewSession}
        title="New session from this project"
        aria-label="New session from this project"
      >
        +
      </button>
      <button
        className="tab-close"
        onClick={handleClose}
        title="Close tab"
        aria-label="Close tab"
      >
        ×
      </button>
    </div>
  )
})

interface TerminalTabsProps {
  tabs: OpenTab[]
  activeTabId: string | null
  onSelectTab: (id: string) => void
  onCloseTab: (id: string) => void
  onNewSession: (projectPath: string) => void
  swipeContainerRef?: RefObject<HTMLElement>  // For mobile swipe gestures
  onOpenSidebar?: () => void  // For mobile right-edge swipe
}

export function TerminalTabs({
  tabs,
  activeTabId,
  onSelectTab,
  onCloseTab,
  onNewSession,
  swipeContainerRef,
  onOpenSidebar
}: TerminalTabsProps) {
  const { isMobile } = useIsMobile()

  // Calculate current tab index
  const currentIndex = tabs.findIndex(t => t.id === activeTabId)

  // Navigation helpers
  const goToNextTab = useCallback(() => {
    if (tabs.length <= 1) return
    const idx = currentIndex === -1 ? 0 : currentIndex
    const newIndex = (idx + 1) % tabs.length
    onSelectTab(tabs[newIndex].id)
  }, [tabs, currentIndex, onSelectTab])

  const goToPrevTab = useCallback(() => {
    if (tabs.length <= 1) return
    const idx = currentIndex === -1 ? 0 : currentIndex
    const newIndex = (idx - 1 + tabs.length) % tabs.length
    onSelectTab(tabs[newIndex].id)
  }, [tabs, currentIndex, onSelectTab])

  const goToTabByIndex = useCallback((index: number) => {
    if (index >= 0 && index < tabs.length) {
      onSelectTab(tabs[index].id)
    }
  }, [tabs, onSelectTab])

  // Setup swipe gesture for mobile (using provided container ref)
  useSwipeGesture(swipeContainerRef as RefObject<HTMLElement>, {
    onSwipeLeft: goToNextTab,
    onSwipeRight: goToPrevTab,
    onSwipeRightEdge: onOpenSidebar,
  })

  const handleWheel = useCallback((e: React.WheelEvent) => {
    if (tabs.length <= 1) return
    if (currentIndex === -1) return

    // Scroll down (positive deltaY) = next tab, scroll up = previous tab
    const direction = e.deltaY > 0 ? 1 : -1
    const newIndex = (currentIndex + direction + tabs.length) % tabs.length
    onSelectTab(tabs[newIndex].id)
  }, [tabs, currentIndex, onSelectTab])

  // Mobile: render SwipeDots instead of full tab bar
  if (isMobile) {
    return (
      <SwipeDots
        current={currentIndex === -1 ? 0 : currentIndex}
        total={tabs.length}
        onDotClick={goToTabByIndex}
      />
    )
  }

  // Desktop: render standard tab bar
  return (
    <div className="tabs-bar" onWheel={handleWheel} role="tablist" aria-label="Terminal sessions">
      {tabs.map((tab) => (
        <TabItem
          key={tab.id}
          tab={tab}
          isActive={tab.id === activeTabId}
          onSelect={onSelectTab}
          onClose={onCloseTab}
          onNewSession={onNewSession}
        />
      ))}
    </div>
  )
}

import { useEffect } from 'react'
import type { Api } from '../api'
import type { BackendId } from '../api/types'
import type { AppSettings } from './useSettings'
import { useWorkspaceStore, OpenTab, Project } from '../stores/workspace'

interface UseApiListenersOptions {
  api: Api
  projects: Project[]
  settings: AppSettings | null
  addTab: (tab: OpenTab) => void
  updateTab: (id: string, updates: Partial<OpenTab>) => void
  setActiveTab: (id: string) => void
}

export function useApiListeners({
  api,
  projects,
  settings,
  addTab,
  updateTab,
  setActiveTab
}: UseApiListenersOptions): void {
  // Listen for API requests to open new sessions
  useEffect(() => {
    const unsubscribe = api.onApiOpenSession(async ({ projectPath, autoClose, model }: { projectPath: string; autoClose?: boolean; model?: string }) => {
      // Open a new session for this project (API-triggered)
      const modelLabel = model && model !== 'default' ? ` [${model}]` : ''
      const title = `${projectPath.split(/[/\\]/).pop() || projectPath} - API${modelLabel}${autoClose ? ' (auto-close)' : ''}`

      // Get project and determine effective backend
      const project = projects.find((p) => p.path === projectPath)

      const effectiveBackend = (project?.backend && project.backend !== 'default'
        ? project.backend
        : (settings?.backend && settings.backend !== 'default'
          ? settings.backend
          : 'claude')) as BackendId

      try {
        // Always install TTS instructions so Claude uses <tts> tags
        await api.ttsInstallInstructions?.(projectPath)

        const ptyId = await api.spawnPty(projectPath, undefined, model, effectiveBackend)
        addTab({
          id: ptyId,
          projectPath,
          title,
          ptyId,
          backend: effectiveBackend
        })
      } catch (e: any) {
        console.error('Failed to spawn PTY for API request:', e)
      }
    })

    return unsubscribe
  }, [api, addTab, projects, settings?.backend])

  // Listen for PTY recreation events
  useEffect(() => {
    const unsubscribe = api.onPtyRecreated(({ oldId, newId, backend }) => {
      console.log(`PTY recreated: ${oldId} -> ${newId} with backend ${backend}`)
      // Find the tab with the old ID
      const tab = useWorkspaceStore.getState().openTabs.find((t) => t.id === oldId)
      if (tab) {
        // Update the tab with the new ID and backend
        updateTab(oldId, { id: newId, ptyId: newId, backend })
        // If it was the active tab, update the active tab ID
        if (useWorkspaceStore.getState().activeTabId === oldId) {
          setActiveTab(newId)
        }
      }
    })
    return unsubscribe
  }, [api, updateTab, setActiveTab])
}

/**
 * HTTP API Client
 *
 * Provides an HTTP/WebSocket-based API client that mirrors the electronAPI interface.
 * This allows the same UI code to work with either Electron IPC or HTTP transport.
 */

import { HostConfig } from '../hostConfig.js'
import { WebSocketManager } from './websocket-manager.js'
